import{_ as i,a as t}from"./chunks/wechat-group-qrcode.D7QkRNzJ.js";import{_ as a,o as e,c as r,ag as l}from"./chunks/framework.Dcoxob_B.js";const b=JSON.parse('{"title":"OpenViking 团队与组织","description":"","frontmatter":{"_rawMarkdown":"# OpenViking 团队与组织\\n\\n## 项目概述\\n\\nOpenViking 是由字节跳动公司火山引擎 Viking 团队发起并维护的开源项目，致力于为 AI Agent 生态系统构建强大的上下文工程基础设施。作为新一代的上下文数据库，OpenViking 通过统一的数据抽象层、智能的语义解析引擎和高性能的混合检索系统，为各类 AI 应用提供坚实可靠的后端支撑。\\n\\n## 团队介绍\\n\\n### Viking 团队背景\\n\\nViking 团队隶属于字节跳动火山引擎，是专注于非结构化信息处理和智能检索领域的核心技术团队。团队汇聚了数十名在分布式系统、机器学习、数据工程和人工智能算法等领域的资深专家，在上下文工程技术方面积累了丰富的商业化实践经验。\\n\\n#### 核心技术能力\\n\\n**大规模向量检索系统**\\n- 支撑亿级向量数据的实时检索与相似度计算\\n- 具备毫秒级响应能力，满足高并发业务场景需求\\n- 支持混合检索策略，结合语义相似性与关键词匹配\\n\\n**多模态内容理解引擎**\\n- 支持文本、图像、音频、视频等多种数据类型的智能解析\\n- 实现跨模态语义关联与内容理解\\n- 提供统一的内容抽象与语义表示\\n\\n**分布式系统架构设计**\\n- 具备构建高可用、可扩展分布式系统的丰富实践经验\\n- 支持弹性伸缩与故障自动恢复机制\\n- 实现数据一致性与系统性能的最佳平衡\\n\\n### 发展历程与技术演进\\n\\nViking 团队在上下文工程领域的探索历程，体现了我们对技术创新与产业应用的持续追求，而随着 AI Agent 应用生态的快速发展，我们计划将 OpenViking 项目作为新理念和新思路的验证平台，实现公开构建，与开源社区一道构建负责任的 AI 应用软件栈。\\n\\n| 时间阶段 | 里程碑事件 | 技术突破与产业影响 |\\n|----------|-----------|-------------------|\\n| **2019-2023** | VikingDB 向量数据库在字节跳动内部大规模应用 | 支撑了公司内部多个核心产品的非结构化信息检索需求，积累了大规模向量检索的工程实践经验，验证了向量数据库在真实业务场景中的技术价值 |\\n| **2024年** | 推出面向开发者的产品矩阵：VikingDB、Viking知识库、Viking记忆库 | 在火山引擎公有云平台正式提供服务，已成功支撑数千家企业客户开发 AI 原生应用，标志着上下文工程技术从内部工具向商业化产品的成功转型 |\\n| **2025年** | 扩展至 AI 搜索、知识助手等上层应用产品 | 构建了从基础设施到应用层的完整产品矩阵，进一步验证了上下文工程技术在不同业务场景中的商业价值，形成了技术到产品的完整闭环 |\\n| **2025年末** | 开源 [MineContext](https://github.com/volcengine/MineContext) 项目 | 探索主动式服务的 AI 应用模式，验证个人上下文工程的技术理念，为 OpenViking 的开源积累了社区运营经验 |\\n| **2026年初** | 开源 OpenViking 项目 | 推出全新设计的上下文数据库架构，为全球 AI Agent 生态系统提供开源基础设施，标志着 Viking 团队从商业产品提供商向开源技术贡献者的战略转变 |\\n\\n### 学术合作与产学研结合\\n\\nOpenViking 项目自启动之初就与国内外顶尖高校和研究机构建立了深度的学术合作关系，共同探索适用于 AI 时代的上下文数据库设计范式与技术最佳实践。这种产学研结合的模式，确保了项目在保持技术先进性的同时，也能够紧密结合实际应用需求。\\n\\n我们诚挚感谢以下学者的宝贵贡献与技术指导，共同发起了 OpenViking 项目：\\n\\n- 中国人民大学信息学院副教授孙亚辉老师\\n- 浙江大学软件学院教授高云君老师，研究员朱轶凡、葛丛丛老师\\n- 上海交通大学人工智能学院副教授，无问芯穹联合创始人兼首席科学家戴国浩老师\\n\\n我们与学术界的合作模式包括：\\n- **联合研究项目**：共同开展上下文工程技术的前沿研究\\n- **技术研讨会**：定期组织学术交流与技术方案评审\\n- **人才培养**：为研究生提供实践平台与研究课题\\n- **成果转化**：将学术研究成果转化为工程实现的最佳实践\\n\\n## 开源组织建设\\n\\n### 项目发展阶段\\n\\nOpenViking 目前处于项目发展的早期阶段，我们将其划分为三个关键发展阶段：\\n\\n- 第一阶段：基础能力建设\\n在开源后的初始阶段，我们将专注于构建坚实的技术基础，包括上下文数据库的核心协议、接口、AI Agent 设施等，并且提供一个可靠完整的最小实现。\\n\\n- 第二阶段：生态扩展\\n建立插件生态系统，支持第三方功能扩展、推动与主流 AI 框架和工具的深度集成，并扩展企业级功能，满足规模化部署需求\\n\\n- 第三阶段：产业应用\\n形成行业技术标准与最佳实践、建立认证体系与合作伙伴生态、推动上下文工程技术在更多产业场景的落地应用\\n\\n### 治理架构与决策机制\\n\\n基于项目的长期发展规划，我们尝试建立分层的治理架构：\\n\\n#### 开源治理委员会\\nOpenViking 项目由一个专业的开源治理委员会负责整体战略规划与技术决策，该委员会由项目的核心贡献者与领域专家组成，主要职责包括：\\n\\n**战略规划职能**\\n- 制定项目的长期技术路线图与发展愿景\\n- 确定版本发布计划与功能优先级\\n- 评估技术决策对项目生态的长期影响\\n\\n**技术治理职能**\\n- 建立并维护代码质量标准与工程规范\\n- 审核核心架构变更与重大功能实现\\n- 确保技术实现的可持续性与向后兼容性\\n\\n**社区发展职能**\\n- 制定社区发展策略与贡献者成长路径\\n- 组织技术交流活动与开发者大会\\n- 建立社区激励机制与荣誉体系\\n\\n**生态合作职能**\\n- 建立与相关开源项目的技术合作关系\\n- 推动与商业产品的集成与认证\\n- 管理项目的知识产权与许可证合规\\n\\n#### 委员会核心成员构成\\n当前开源治理委员会的核心成员包括以下技术专家：\\nHaojie Qin, Jiahui Zhou, Linggang Wang, Maojia Sheng, Yaohui Sun\\n\\n为确保治理结构的开放性与多样性，我们欢迎符合条件的社区贡献者通过未来的提名与选举程序加入治理委员会。\\n\\n## 社区参与\\n\\n### 加入社区\\n\\n我们诚挚邀请全球开发者加入 OpenViking 社区，共同构建下一代上下文工程基础设施。您可以通过以下方式参与：\\n\\n#### 即时交流\\n\\n##### 飞书群\\n\\n扫描下方二维码加入飞书群组，与核心开发团队实时交流：\\n\\n![飞书扫码加群](/lark-group-qrcode.png)\\n\\n*注：加入群组前请确保已安装 [飞书客户端](https://www.feishu.cn/)*\\n\\n##### 微信群\\n\\n扫描下方二维码添加小助手微信，备注「OpenViking」后即可加入微信交流群：\\n\\n![微信扫码加群](/wechat-group-qrcode.png)\\n\\n**Discord**\\n\\n[加入 Discord 服务器](https://discord.com/invite/eHvx8E9XF3)\\n\\n**X**\\n\\n[关注我们的动态](https://x.com/openvikingai)\\n\\n### 参与方式\\n\\n我们提供多种参与渠道，满足不同开发者的协作需求：\\n\\n#### 1. 代码贡献\\n- **提交 Issue**：报告 Bug、提出功能建议或讨论技术方案\\n- **提交 Pull Request**：贡献代码改进、文档更新或测试用例\\n- **代码审查**：参与代码审查，帮助提升代码质量\\n\\n#### 2. 文档贡献\\n- **完善文档**：补充用户指南、API 文档或开发教程\\n- **翻译支持**：协助将文档翻译为其他语言版本\\n- **示例代码**：提供更多使用示例和最佳实践\\n\\n#### 3. 社区支持\\n- **技术分享**：在社区中分享使用经验和技术见解\\n- **问题解答**：帮助其他开发者解决使用中的问题\\n- **生态建设**：推动 OpenViking 与其他开源项目的集成\\n\\n#### 4. 生态拓展\\n- **插件开发**：开发第三方插件或扩展功能\\n- **集成适配**：推动 OpenViking 与主流框架的深度集成\\n- **应用案例**：分享在实际项目中的应用经验\\n\\n## 讨论与协作机制\\n\\n### 正式渠道\\n\\n#### GitHub 平台\\n- **Issues**：用于功能建议、Bug 报告和技术讨论\\n- **Pull Requests**：用于代码贡献和文档更新\\n- **Discussions**：用于技术方案讨论和社区交流\\n\\n#### 代码仓库\\n- **主仓库**：`https://github.com/volcengine/openviking`\\n- **Issue 追踪**：`https://github.com/volcengine/openviking/issues`\\n\\n### 实时交流\\n\\n#### 飞书群组\\n- **技术讨论**：实时技术交流与问题解答\\n- **代码审查**：快速反馈和协作开发\\n- **活动通知**：社区活动和技术分享通知\\n\\n### 社交媒体\\n\\n我们关注各大技术社区和社交媒体平台，及时回应用户反馈：\\n- **技术博客**：定期发布技术文章和项目进展\\n- **社交媒体**：在相关平台分享项目动态和使用案例\\n- **技术会议**：参与行业会议，分享技术实践\\n\\n### 社区目标\\n\\n我们期望通过开源社区实现以下目标：\\n\\n1. **技术民主化**：让更多开发者能够使用先进的上下文工程技术\\n2. **创新加速**：通过社区协作加速技术创新和产品迭代\\n3. **标准建立**：推动上下文工程领域的技术标准和最佳实践\\n4. **人才培养**：培养更多上下文工程领域的技术人才\\n\\n### 合作开放\\n\\nOpenViking 项目向所有开发者、研究机构和商业公司开放合作机会。我们期待：\\n\\n- **技术合作**：与学术界和产业界开展深度技术合作\\n- **生态集成**：与相关开源项目和商业产品建立集成关系\\n- **应用推广**：共同推动上下文工程技术在更多场景的应用\\n\\n---\\n\\n**加入我们，共同构建 AI Agent 时代的上下文基础设施！**\\n"},"headers":[],"relativePath":"zh/about/01-about-us.md","filePath":"zh/about/01-about-us.md","lastUpdated":1777024806000}'),o={name:"zh/about/01-about-us.md"};function s(g,n,h,u,d,p){return e(),r("div",null,[...n[0]||(n[0]=[l('<h1 id="openviking-团队与组织" tabindex="-1">OpenViking 团队与组织 <a class="header-anchor" href="#openviking-团队与组织" aria-label="Permalink to &quot;OpenViking 团队与组织&quot;">​</a></h1><h2 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to &quot;项目概述&quot;">​</a></h2><p>OpenViking 是由字节跳动公司火山引擎 Viking 团队发起并维护的开源项目，致力于为 AI Agent 生态系统构建强大的上下文工程基础设施。作为新一代的上下文数据库，OpenViking 通过统一的数据抽象层、智能的语义解析引擎和高性能的混合检索系统，为各类 AI 应用提供坚实可靠的后端支撑。</p><h2 id="团队介绍" tabindex="-1">团队介绍 <a class="header-anchor" href="#团队介绍" aria-label="Permalink to &quot;团队介绍&quot;">​</a></h2><h3 id="viking-团队背景" tabindex="-1">Viking 团队背景 <a class="header-anchor" href="#viking-团队背景" aria-label="Permalink to &quot;Viking 团队背景&quot;">​</a></h3><p>Viking 团队隶属于字节跳动火山引擎，是专注于非结构化信息处理和智能检索领域的核心技术团队。团队汇聚了数十名在分布式系统、机器学习、数据工程和人工智能算法等领域的资深专家，在上下文工程技术方面积累了丰富的商业化实践经验。</p><h4 id="核心技术能力" tabindex="-1">核心技术能力 <a class="header-anchor" href="#核心技术能力" aria-label="Permalink to &quot;核心技术能力&quot;">​</a></h4><p><strong>大规模向量检索系统</strong></p><ul><li>支撑亿级向量数据的实时检索与相似度计算</li><li>具备毫秒级响应能力，满足高并发业务场景需求</li><li>支持混合检索策略，结合语义相似性与关键词匹配</li></ul><p><strong>多模态内容理解引擎</strong></p><ul><li>支持文本、图像、音频、视频等多种数据类型的智能解析</li><li>实现跨模态语义关联与内容理解</li><li>提供统一的内容抽象与语义表示</li></ul><p><strong>分布式系统架构设计</strong></p><ul><li>具备构建高可用、可扩展分布式系统的丰富实践经验</li><li>支持弹性伸缩与故障自动恢复机制</li><li>实现数据一致性与系统性能的最佳平衡</li></ul><h3 id="发展历程与技术演进" tabindex="-1">发展历程与技术演进 <a class="header-anchor" href="#发展历程与技术演进" aria-label="Permalink to &quot;发展历程与技术演进&quot;">​</a></h3><p>Viking 团队在上下文工程领域的探索历程，体现了我们对技术创新与产业应用的持续追求，而随着 AI Agent 应用生态的快速发展，我们计划将 OpenViking 项目作为新理念和新思路的验证平台，实现公开构建，与开源社区一道构建负责任的 AI 应用软件栈。</p><table tabindex="0"><thead><tr><th>时间阶段</th><th>里程碑事件</th><th>技术突破与产业影响</th></tr></thead><tbody><tr><td><strong>2019-2023</strong></td><td>VikingDB 向量数据库在字节跳动内部大规模应用</td><td>支撑了公司内部多个核心产品的非结构化信息检索需求，积累了大规模向量检索的工程实践经验，验证了向量数据库在真实业务场景中的技术价值</td></tr><tr><td><strong>2024年</strong></td><td>推出面向开发者的产品矩阵：VikingDB、Viking知识库、Viking记忆库</td><td>在火山引擎公有云平台正式提供服务，已成功支撑数千家企业客户开发 AI 原生应用，标志着上下文工程技术从内部工具向商业化产品的成功转型</td></tr><tr><td><strong>2025年</strong></td><td>扩展至 AI 搜索、知识助手等上层应用产品</td><td>构建了从基础设施到应用层的完整产品矩阵，进一步验证了上下文工程技术在不同业务场景中的商业价值，形成了技术到产品的完整闭环</td></tr><tr><td><strong>2025年末</strong></td><td>开源 <a href="https://github.com/volcengine/MineContext" target="_blank" rel="noreferrer">MineContext</a> 项目</td><td>探索主动式服务的 AI 应用模式，验证个人上下文工程的技术理念，为 OpenViking 的开源积累了社区运营经验</td></tr><tr><td><strong>2026年初</strong></td><td>开源 OpenViking 项目</td><td>推出全新设计的上下文数据库架构，为全球 AI Agent 生态系统提供开源基础设施，标志着 Viking 团队从商业产品提供商向开源技术贡献者的战略转变</td></tr></tbody></table><h3 id="学术合作与产学研结合" tabindex="-1">学术合作与产学研结合 <a class="header-anchor" href="#学术合作与产学研结合" aria-label="Permalink to &quot;学术合作与产学研结合&quot;">​</a></h3><p>OpenViking 项目自启动之初就与国内外顶尖高校和研究机构建立了深度的学术合作关系，共同探索适用于 AI 时代的上下文数据库设计范式与技术最佳实践。这种产学研结合的模式，确保了项目在保持技术先进性的同时，也能够紧密结合实际应用需求。</p><p>我们诚挚感谢以下学者的宝贵贡献与技术指导，共同发起了 OpenViking 项目：</p><ul><li>中国人民大学信息学院副教授孙亚辉老师</li><li>浙江大学软件学院教授高云君老师，研究员朱轶凡、葛丛丛老师</li><li>上海交通大学人工智能学院副教授，无问芯穹联合创始人兼首席科学家戴国浩老师</li></ul><p>我们与学术界的合作模式包括：</p><ul><li><strong>联合研究项目</strong>：共同开展上下文工程技术的前沿研究</li><li><strong>技术研讨会</strong>：定期组织学术交流与技术方案评审</li><li><strong>人才培养</strong>：为研究生提供实践平台与研究课题</li><li><strong>成果转化</strong>：将学术研究成果转化为工程实现的最佳实践</li></ul><h2 id="开源组织建设" tabindex="-1">开源组织建设 <a class="header-anchor" href="#开源组织建设" aria-label="Permalink to &quot;开源组织建设&quot;">​</a></h2><h3 id="项目发展阶段" tabindex="-1">项目发展阶段 <a class="header-anchor" href="#项目发展阶段" aria-label="Permalink to &quot;项目发展阶段&quot;">​</a></h3><p>OpenViking 目前处于项目发展的早期阶段，我们将其划分为三个关键发展阶段：</p><ul><li><p>第一阶段：基础能力建设 在开源后的初始阶段，我们将专注于构建坚实的技术基础，包括上下文数据库的核心协议、接口、AI Agent 设施等，并且提供一个可靠完整的最小实现。</p></li><li><p>第二阶段：生态扩展 建立插件生态系统，支持第三方功能扩展、推动与主流 AI 框架和工具的深度集成，并扩展企业级功能，满足规模化部署需求</p></li><li><p>第三阶段：产业应用 形成行业技术标准与最佳实践、建立认证体系与合作伙伴生态、推动上下文工程技术在更多产业场景的落地应用</p></li></ul><h3 id="治理架构与决策机制" tabindex="-1">治理架构与决策机制 <a class="header-anchor" href="#治理架构与决策机制" aria-label="Permalink to &quot;治理架构与决策机制&quot;">​</a></h3><p>基于项目的长期发展规划，我们尝试建立分层的治理架构：</p><h4 id="开源治理委员会" tabindex="-1">开源治理委员会 <a class="header-anchor" href="#开源治理委员会" aria-label="Permalink to &quot;开源治理委员会&quot;">​</a></h4><p>OpenViking 项目由一个专业的开源治理委员会负责整体战略规划与技术决策，该委员会由项目的核心贡献者与领域专家组成，主要职责包括：</p><p><strong>战略规划职能</strong></p><ul><li>制定项目的长期技术路线图与发展愿景</li><li>确定版本发布计划与功能优先级</li><li>评估技术决策对项目生态的长期影响</li></ul><p><strong>技术治理职能</strong></p><ul><li>建立并维护代码质量标准与工程规范</li><li>审核核心架构变更与重大功能实现</li><li>确保技术实现的可持续性与向后兼容性</li></ul><p><strong>社区发展职能</strong></p><ul><li>制定社区发展策略与贡献者成长路径</li><li>组织技术交流活动与开发者大会</li><li>建立社区激励机制与荣誉体系</li></ul><p><strong>生态合作职能</strong></p><ul><li>建立与相关开源项目的技术合作关系</li><li>推动与商业产品的集成与认证</li><li>管理项目的知识产权与许可证合规</li></ul><h4 id="委员会核心成员构成" tabindex="-1">委员会核心成员构成 <a class="header-anchor" href="#委员会核心成员构成" aria-label="Permalink to &quot;委员会核心成员构成&quot;">​</a></h4><p>当前开源治理委员会的核心成员包括以下技术专家： Haojie Qin, Jiahui Zhou, Linggang Wang, Maojia Sheng, Yaohui Sun</p><p>为确保治理结构的开放性与多样性，我们欢迎符合条件的社区贡献者通过未来的提名与选举程序加入治理委员会。</p><h2 id="社区参与" tabindex="-1">社区参与 <a class="header-anchor" href="#社区参与" aria-label="Permalink to &quot;社区参与&quot;">​</a></h2><h3 id="加入社区" tabindex="-1">加入社区 <a class="header-anchor" href="#加入社区" aria-label="Permalink to &quot;加入社区&quot;">​</a></h3><p>我们诚挚邀请全球开发者加入 OpenViking 社区，共同构建下一代上下文工程基础设施。您可以通过以下方式参与：</p><h4 id="即时交流" tabindex="-1">即时交流 <a class="header-anchor" href="#即时交流" aria-label="Permalink to &quot;即时交流&quot;">​</a></h4><h5 id="飞书群" tabindex="-1">飞书群 <a class="header-anchor" href="#飞书群" aria-label="Permalink to &quot;飞书群&quot;">​</a></h5><p>扫描下方二维码加入飞书群组，与核心开发团队实时交流：</p><p><img src="'+i+'" alt="飞书扫码加群"></p><p><em>注：加入群组前请确保已安装 <a href="https://www.feishu.cn/" target="_blank" rel="noreferrer">飞书客户端</a></em></p><h5 id="微信群" tabindex="-1">微信群 <a class="header-anchor" href="#微信群" aria-label="Permalink to &quot;微信群&quot;">​</a></h5><p>扫描下方二维码添加小助手微信，备注「OpenViking」后即可加入微信交流群：</p><p><img src="'+t+'" alt="微信扫码加群"></p><p><strong>Discord</strong></p><p><a href="https://discord.com/invite/eHvx8E9XF3" target="_blank" rel="noreferrer">加入 Discord 服务器</a></p><p><strong>X</strong></p><p><a href="https://x.com/openvikingai" target="_blank" rel="noreferrer">关注我们的动态</a></p><h3 id="参与方式" tabindex="-1">参与方式 <a class="header-anchor" href="#参与方式" aria-label="Permalink to &quot;参与方式&quot;">​</a></h3><p>我们提供多种参与渠道，满足不同开发者的协作需求：</p><h4 id="_1-代码贡献" tabindex="-1">1. 代码贡献 <a class="header-anchor" href="#_1-代码贡献" aria-label="Permalink to &quot;1. 代码贡献&quot;">​</a></h4><ul><li><strong>提交 Issue</strong>：报告 Bug、提出功能建议或讨论技术方案</li><li><strong>提交 Pull Request</strong>：贡献代码改进、文档更新或测试用例</li><li><strong>代码审查</strong>：参与代码审查，帮助提升代码质量</li></ul><h4 id="_2-文档贡献" tabindex="-1">2. 文档贡献 <a class="header-anchor" href="#_2-文档贡献" aria-label="Permalink to &quot;2. 文档贡献&quot;">​</a></h4><ul><li><strong>完善文档</strong>：补充用户指南、API 文档或开发教程</li><li><strong>翻译支持</strong>：协助将文档翻译为其他语言版本</li><li><strong>示例代码</strong>：提供更多使用示例和最佳实践</li></ul><h4 id="_3-社区支持" tabindex="-1">3. 社区支持 <a class="header-anchor" href="#_3-社区支持" aria-label="Permalink to &quot;3. 社区支持&quot;">​</a></h4><ul><li><strong>技术分享</strong>：在社区中分享使用经验和技术见解</li><li><strong>问题解答</strong>：帮助其他开发者解决使用中的问题</li><li><strong>生态建设</strong>：推动 OpenViking 与其他开源项目的集成</li></ul><h4 id="_4-生态拓展" tabindex="-1">4. 生态拓展 <a class="header-anchor" href="#_4-生态拓展" aria-label="Permalink to &quot;4. 生态拓展&quot;">​</a></h4><ul><li><strong>插件开发</strong>：开发第三方插件或扩展功能</li><li><strong>集成适配</strong>：推动 OpenViking 与主流框架的深度集成</li><li><strong>应用案例</strong>：分享在实际项目中的应用经验</li></ul><h2 id="讨论与协作机制" tabindex="-1">讨论与协作机制 <a class="header-anchor" href="#讨论与协作机制" aria-label="Permalink to &quot;讨论与协作机制&quot;">​</a></h2><h3 id="正式渠道" tabindex="-1">正式渠道 <a class="header-anchor" href="#正式渠道" aria-label="Permalink to &quot;正式渠道&quot;">​</a></h3><h4 id="github-平台" tabindex="-1">GitHub 平台 <a class="header-anchor" href="#github-平台" aria-label="Permalink to &quot;GitHub 平台&quot;">​</a></h4><ul><li><strong>Issues</strong>：用于功能建议、Bug 报告和技术讨论</li><li><strong>Pull Requests</strong>：用于代码贡献和文档更新</li><li><strong>Discussions</strong>：用于技术方案讨论和社区交流</li></ul><h4 id="代码仓库" tabindex="-1">代码仓库 <a class="header-anchor" href="#代码仓库" aria-label="Permalink to &quot;代码仓库&quot;">​</a></h4><ul><li><strong>主仓库</strong>：<code>https://github.com/volcengine/openviking</code></li><li><strong>Issue 追踪</strong>：<code>https://github.com/volcengine/openviking/issues</code></li></ul><h3 id="实时交流" tabindex="-1">实时交流 <a class="header-anchor" href="#实时交流" aria-label="Permalink to &quot;实时交流&quot;">​</a></h3><h4 id="飞书群组" tabindex="-1">飞书群组 <a class="header-anchor" href="#飞书群组" aria-label="Permalink to &quot;飞书群组&quot;">​</a></h4><ul><li><strong>技术讨论</strong>：实时技术交流与问题解答</li><li><strong>代码审查</strong>：快速反馈和协作开发</li><li><strong>活动通知</strong>：社区活动和技术分享通知</li></ul><h3 id="社交媒体" tabindex="-1">社交媒体 <a class="header-anchor" href="#社交媒体" aria-label="Permalink to &quot;社交媒体&quot;">​</a></h3><p>我们关注各大技术社区和社交媒体平台，及时回应用户反馈：</p><ul><li><strong>技术博客</strong>：定期发布技术文章和项目进展</li><li><strong>社交媒体</strong>：在相关平台分享项目动态和使用案例</li><li><strong>技术会议</strong>：参与行业会议，分享技术实践</li></ul><h3 id="社区目标" tabindex="-1">社区目标 <a class="header-anchor" href="#社区目标" aria-label="Permalink to &quot;社区目标&quot;">​</a></h3><p>我们期望通过开源社区实现以下目标：</p><ol><li><strong>技术民主化</strong>：让更多开发者能够使用先进的上下文工程技术</li><li><strong>创新加速</strong>：通过社区协作加速技术创新和产品迭代</li><li><strong>标准建立</strong>：推动上下文工程领域的技术标准和最佳实践</li><li><strong>人才培养</strong>：培养更多上下文工程领域的技术人才</li></ol><h3 id="合作开放" tabindex="-1">合作开放 <a class="header-anchor" href="#合作开放" aria-label="Permalink to &quot;合作开放&quot;">​</a></h3><p>OpenViking 项目向所有开发者、研究机构和商业公司开放合作机会。我们期待：</p><ul><li><strong>技术合作</strong>：与学术界和产业界开展深度技术合作</li><li><strong>生态集成</strong>：与相关开源项目和商业产品建立集成关系</li><li><strong>应用推广</strong>：共同推动上下文工程技术在更多场景的应用</li></ul><hr><p><strong>加入我们，共同构建 AI Agent 时代的上下文基础设施！</strong></p>',86)])])}const q=a(o,[["render",s]]);export{b as __pageData,q as default};
